import React, { useRef, MutableRefObject } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { OrbitControls } from '@react-three/drei';
import { Organism } from '../../domain/types';
import { CreatureView } from './CreatureView';
import { FoodView } from './FoodView';
import * as THREE from 'three';
import { OrbitControls as OrbitControlsImpl } from 'three-stdlib';

interface SimulationLayerProps {
  population: Organism[];
  showBestOnly: boolean;
  visionRadius: number;
}

// COMPONENT: StableLeaderTracker
// Logic: Locks onto a leader and sticks with them to prevent camera jitter.
// Only switches if the leader dies or is overtaken by a significant margin (Hysteresis).
const StableLeaderTracker: React.FC<{ 
    population: Organism[], 
    leaderRef: MutableRefObject<Organism | null> 
}> = ({ population, leaderRef }) => {

    // Track the ID locally to detect death/switching
    const currentLeaderId = useRef<string | null>(null);

    useFrame(() => {
        if (!population.length) return;

        // 1. Find the current best candidate
        let bestCandidate: Organism | null = null;
        let bestZ = -Infinity;

        // Simple heuristic: furthest forward alive creature
        for (const org of population) {
            if (!org.isAlive) continue;

            // Calculate center Z
            let cz = 0;
            for(const n of org.nodes) cz += n.pos.z;
            cz /= org.nodes.length;

            if (cz > bestZ) {
                bestZ = cz;
                bestCandidate = org;
            }
        }

        // Fallback to best dead if everyone is dead
        if (!bestCandidate) {
             let bestDeadZ = -Infinity;
             for (const org of population) {
                let cz = 0;
                for(const n of org.nodes) cz += n.pos.z;
                cz /= org.nodes.length;
                if (cz > bestDeadZ) { bestDeadZ = cz; bestCandidate = org; }
             }
        }

        if (!bestCandidate) return;

        // 2. Stability Logic
        const current = leaderRef.current;

        // If we have no leader, or current leader is dead/gone, take the candidate
        if (!current || !current.isAlive || !population.find(o => o.id === current.id)) {
            leaderRef.current = bestCandidate;
            currentLeaderId.current = bestCandidate.id;
            return;
        }

        // If locked leader is still alive, check if we should switch
        // HYSTERESIS: Only switch if the candidate is significantly ahead (e.g., 2.0 units)
        // This prevents jitter when two creatures are neck-and-neck
        let currentZ = 0;
        for(const n of current.nodes) currentZ += n.pos.z;
        currentZ /= current.nodes.length;

        if (bestZ > currentZ + 4.0) {
            leaderRef.current = bestCandidate;
            currentLeaderId.current = bestCandidate.id;
        }
    });
    return null;
};

// COMPONENT: CameraDirector
const CameraDirector: React.FC<{ leaderRef: MutableRefObject<Organism | null> }> = ({ leaderRef }) => {
    const { camera } = useThree();
    const controlsRef = useRef<OrbitControlsImpl>(null);
    const targetRef = useRef(new THREE.Vector3(0, 0, 0));

    useFrame(() => {
        const leader = leaderRef.current;
        if (!leader) return;

        // Calculate Target Position
        let cx = 0, cy = 0, cz = 0;
        const len = leader.nodes.length;
        for (const n of leader.nodes) {
            cx += n.pos.x;
            cy += n.pos.y;
            cz += n.pos.z;
        }
        const center = new THREE.Vector3(cx/len, cy/len, cz/len);

        // Smoothly Interpolate Camera & Target
        // We use a slightly faster lerp for the target to keep the creature in frame during fast forward
        targetRef.current.lerp(center, 0.15);

        if (controlsRef.current) {
            const offset = camera.position.clone().sub(controlsRef.current.target);
            controlsRef.current.target.copy(targetRef.current);
            camera.position.copy(targetRef.current).add(offset);
            controlsRef.current.update();
        }
    });

    return <OrbitControls ref={controlsRef} makeDefault maxPolarAngle={Math.PI / 2 - 0.1} />;
};

export const SimulationLayer: React.FC<SimulationLayerProps> = ({ population, showBestOnly, visionRadius }) => {
  const leaderRef = useRef<Organism | null>(null);

  return (
    <group>
        <StableLeaderTracker population={population} leaderRef={leaderRef} />
        <CameraDirector leaderRef={leaderRef} />

        {population.map((org) => (
            <CreatureView 
              key={org.id} 
              organism={org} 
              leaderRef={leaderRef}
              showBestOnly={showBestOnly}
              visionRadius={visionRadius}
            />
        ))}

        <FoodView leaderRef={leaderRef} />
    </group>
  );
};

