import { Organism, Node } from '../types';

export interface IFitnessEvaluator {
    evaluate(organism: Organism, dt: number): void;
    finalize(organism: Organism): void;
    setWeights(foodWeight: number, distanceWeight: number): void;
}

export class StandardFitnessEvaluator implements IFitnessEvaluator {
    private foodWeight: number = 20.0;
    private distanceWeight: number = 20.0;

    setWeights(foodWeight: number, distanceWeight: number) {
        this.foodWeight = foodWeight;
        this.distanceWeight = distanceWeight;
    }

    evaluate(organism: Organism, dt: number): void {
        // Distance Logic (Displacement from initial start point)
        let currentPos = { x: 0, y: 0, z: 0 };
        let startPos = organism.initialHeadPos;

        const head = organism.nodes.find(n => n.isHead);

        if (head) {
            currentPos = head.pos;
        } else if (organism.nodes.length > 0) {
            // Fallback to Center of Mass if no head found (Robustness)
            let cx = 0, cy = 0, cz = 0;
            organism.nodes.forEach(n => { cx+=n.pos.x; cy+=n.pos.y; cz+=n.pos.z; });
            const invLen = 1.0 / organism.nodes.length;
            currentPos = { x: cx*invLen, y: cy*invLen, z: cz*invLen };

            // If we don't have a valid start pos (e.g. legacy), use 0,0,0
            if (!startPos) startPos = { x: 0, y: 0, z: 0 };
        } else {
            return; // Empty organism
        }

        // Use XZ plane distance (Planar travel)
        const dx = currentPos.x - startPos.x;
        const dz = currentPos.z - startPos.z;
        const dist = Math.sqrt(dx*dx + dz*dz);

        organism.distanceTraveled = dist;

        // Fitness = Distance * Weight + Food
        // We evaluate this every frame so real-time fitness is visible
        organism.fitness = (organism.foodEaten * this.foodWeight) + (dist * this.distanceWeight);
    }

    finalize(organism: Organism): void {
        this.evaluate(organism, 0);
    }
}

import React from 'react';

interface StatsOverlayProps {
    status: 'EDITING' | 'SIMULATING';
